                        let v1 = state.get_at(base + i.arg_b()).clone();
                        let v2 = state.get_at(base + i.arg_c()).clone();
                        arith_float_aux(state, ra, &v1, &v2, &mut pc,
                            |a, b| if b == 2.0 { a * a } else { a.powf(b) });
                    }
                    OpCode::Div => {
                        let ra = base + i.arg_a();
                        let v1 = state.get_at(base + i.arg_b()).clone();
                        let v2 = state.get_at(base + i.arg_c()).clone();
                        arith_float_aux(state, ra, &v1, &v2, &mut pc, |a, b| a / b);
